2	/**
3	 * Sample status state machine — single source of truth for the sample lifecycle.
4	 *
5	 * A sample travels in one of two directions:
6	 *   inbound  (factory-origin): requested -> shipped -> ningbo_checked_in
7	 *                              -> ningbo_checked_out -> nyc_checked_in
8	 *   outbound (usa-bought):     nyc_requested -> nyc_checked_out -> ningbo_checked_in
9	 *                              -> ningbo_checked_out -> sent_to_factory
10	 *   customer (china-origin):   ningbo_checked_in -> ningbo_checked_out -> sent_to_customer
11	 *
12	 * Backbone moves (check_in / check_out / ship) have their resulting status
13	 * DERIVED from (direction, current status, office, event_type) — the client
14	 * never supplies the target status for those. The "shared extra" states
15	 * (cancelled / on_hold / damaged / approved) are reached with a status_change
16	 * event whose requested target is validated against a small allow-list.
17	 */
18	
19	const ORIGINS = ['factory_request', 'factory_offer', 'usa_bought', 'customer'];
20	const DIRECTIONS = ['inbound', 'outbound', 'customer'];
21	const OFFICES = ['Ningbo', 'NYC'];
22	const EVENT_TYPES = ['check_in', 'check_out', 'ship', 'receive', 'status_change'];
23	
24	// Shared exception states reachable (almost) any time.
25	const SHARED_EXTRAS = ['cancelled', 'on_hold', 'damaged', 'approved'];
26	// Once here, no further moves are allowed.
27	const TERMINAL_EXTRAS = ['cancelled'];
28	
29	// Origin -> how a freshly created sample starts.
30	const ORIGIN_DEFAULTS = {
31	  factory_request: { direction: 'inbound', initialStatus: 'requested' },
32	  factory_offer: { direction: 'inbound', initialStatus: 'requested' },
33	  usa_bought: { direction: 'outbound', initialStatus: 'nyc_requested' },
34	  customer: { direction: 'customer', initialStatus: 'ningbo_checked_in' }
35	};
36	
37	// Ordered backbone status lists per direction (used for resume-from-hold).
38	const BACKBONE = {
39	  inbound: ['requested', 'shipped', 'ningbo_checked_in', 'ningbo_checked_out', 'nyc_checked_in'],
40	  outbound: ['nyc_requested', 'nyc_checked_out', 'ningbo_checked_in', 'ningbo_checked_out', 'sent_to_factory'],
41	  customer: ['ningbo_checked_in', 'ningbo_checked_out', 'sent_to_customer']
42	};
43	
44	// Backbone transition rules. `office: null` means the office is not checked.
45	const TRANSITIONS = {
46	  inbound: [
47	    { from: 'requested', eventType: 'ship', office: null, to: 'shipped' },
48	    { from: 'shipped', eventType: 'check_in', office: 'Ningbo', to: 'ningbo_checked_in' },
49	    { from: 'ningbo_checked_in', eventType: 'check_out', office: 'Ningbo', to: 'ningbo_checked_out' },
50	    { from: 'ningbo_checked_out', eventType: 'check_in', office: 'NYC', to: 'nyc_checked_in' }
51	  ],
52	  outbound: [
53	    { from: 'nyc_requested', eventType: 'check_out', office: 'NYC', to: 'nyc_checked_out' },
54	    { from: 'nyc_checked_out', eventType: 'check_in', office: 'Ningbo', to: 'ningbo_checked_in' },
55	    { from: 'ningbo_checked_in', eventType: 'check_out', office: 'Ningbo', to: 'ningbo_checked_out' },
56	    { from: 'ningbo_checked_out', eventType: 'ship', office: 'Ningbo', to: 'sent_to_factory' }
57	  ],
58	  customer: [
59	    { from: 'ningbo_checked_in', eventType: 'check_out', office: 'Ningbo', to: 'ningbo_checked_out' },
60	    { from: 'ningbo_checked_out', eventType: 'ship', office: 'Ningbo', to: 'sent_to_customer' }
61	  ]
62	};
63	
64	// All statuses that can ever appear, for validation/migration assertions.
65	const ALL_STATUSES = Array.from(new Set([
66	  ...BACKBONE.inbound,
67	  ...BACKBONE.outbound,
68	  ...SHARED_EXTRAS
69	]));
70	
71	function isBackboneStatus(direction, status) {
72	  return (BACKBONE[direction] || []).includes(status);
73	}
74	
75	/**
76	 * Derive the resulting status for an event, or explain why it is rejected.
77	 * @returns {{ ok: true, toStatus: string }
78	 *          | { ok: false, status: number, error: string }}
79	 */
80	function deriveToStatus({ direction, currentStatus, office, eventType, requestedToStatus }) {
81	  if (!DIRECTIONS.includes(direction)) {
82	    return { ok: false, status: 400, error: `Unknown direction "${direction}"` };
83	  }
84	  if (!EVENT_TYPES.includes(eventType)) {
85	    return { ok: false, status: 400, error: `Unknown event_type "${eventType}"` };
86	  }
87	  if (TERMINAL_EXTRAS.includes(currentStatus)) {
88	    return { ok: false, status: 409, error: `Sample is ${currentStatus}; no further changes allowed` };
89	  }
90	
91	  // Shared-extra / resume moves go through status_change.
92	  if (eventType === 'status_change') {
93	    if (!requestedToStatus) {
94	      return { ok: false, status: 400, error: 'status_change requires a to_status' };
95	    }
96	    if (SHARED_EXTRAS.includes(requestedToStatus)) {
97	      if (requestedToStatus === currentStatus) {
98	        return { ok: false, status: 409, error: `Sample already ${currentStatus}` };
99	      }
100	      return { ok: true, toStatus: requestedToStatus };
101	    }
102	    // Resume from on_hold back onto the backbone.
103	    if (currentStatus === 'on_hold' && isBackboneStatus(direction, requestedToStatus)) {
104	      return { ok: true, toStatus: requestedToStatus };
105	    }
106	    return { ok: false, status: 400, error: `Illegal status_change to "${requestedToStatus}" from "${currentStatus}"` };
107	  }
108	
109	  // Backbone moves: look up the single matching rule.
110	  const rule = (TRANSITIONS[direction] || []).find(r =>
111	    r.from === currentStatus &&
112	    r.eventType === eventType &&
113	    (r.office === null || r.office === office)
114	  );
115	  if (!rule) {
116	    return {
117	      ok: false,
118	      status: 400,
119	      error: `No ${eventType} transition from "${currentStatus}"` +
120	        (office ? ` at ${office}` : '') + ` for ${direction} sample`
121	    };
122	  }
123	  return { ok: true, toStatus: rule.to };
124	}
125	
126	module.exports = {
127	  ORIGINS,
128	  DIRECTIONS,
129	  OFFICES,
130	  EVENT_TYPES,
131	  SHARED_EXTRAS,
132	  TERMINAL_EXTRAS,
133	  ORIGIN_DEFAULTS,
134	  BACKBONE,
135	  TRANSITIONS,
136	  ALL_STATUSES,
137	  isBackboneStatus,
138	  deriveToStatus
139	};
